import 'package:flutter/material.dart';\nimport 'package:flutter_riverpod/flutter_riverpod.dart';\nimport 'package:image_picker/image_picker.dart';\nimport '../../data/models/workflow.dart';\nimport '../../services/workflow_service.dart';\nimport '../../data/auth/auth_provider.dart';\n\nclass TaskDetailPage extends ConsumerStatefulWidget {\n  final WorkflowTask task;\n  final bool isMyTask;\n  final bool showCompletionForm;\n  final VoidCallback onTaskUpdated;\n\n  const TaskDetailPage({\n    super.key,\n    required this.task,\n    required this.isMyTask,\n    this.showCompletionForm = false,\n    required this.onTaskUpdated,\n  });\n\n  @override\n  ConsumerState<TaskDetailPage> createState() => _TaskDetailPageState();\n}\n\nclass _TaskDetailPageState extends ConsumerState<TaskDetailPage> {\n  final WorkflowService workflowService = WorkflowService();\n  final TextEditingController notesController = TextEditingController();\n  final ImagePicker imagePicker = ImagePicker();\n  \n  List<String> _selectedImages = [];\n  int _qualityRating = 5;\n  bool _isLoading = false;\n  WorkflowTask? _currentTask;\n\n  @override\n  void initState() {\n    super.initState();\n    currentTask = widget.task;\n    notesController.text = widget.task.notes ?? '';\n    selectedImages = List.from(widget.task.images);\n    if (widget.showCompletionForm) {\n      WidgetsBinding.instance.addPostFrameCallback((_) {\n        showCompletionDialog();\n      });\n    }\n  }\n\n  @override\n  void dispose() {\n    notesController.dispose();\n    super.dispose();\n  }\n\n  Future<void> refreshTaskDetails() async {\n    final user = ref.read(authProvider);
    final staffId = user?.uid ?? '';
    final token = user?.jwt;
    final updatedTask = await workflowService.getTaskDetails(widget.task.id, staffId, token: token);\n    if (updatedTask != null) {\n      setState(() {\n        currentTask = updatedTask;\n      });\n    }\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    final task = _currentTask ?? widget.task;\n    \n    return Scaffold(\n      appBar: AppBar(\n        title: const Text('Task Details'),\n        backgroundColor: Colors.deepOrange,\n        foregroundColor: Colors.white,\n        actions: [\n          if (widget.isMyTask)\n            PopupMenuButton<String>(\n              onSelected: (value) => handleMenuAction(value, task),\n              itemBuilder: (context) => [\n                if (task.canStart)\n                  const PopupMenuItem(\n                    value: 'start',\n                    child: Row(\n                      children: [\n                        Icon(Icons.play_arrow, color: Colors.green),\n                        SizedBox(width: 8),\n                        Text('Start Task'),\n                      ],\n                    ),\n                  ),\n                if (task.canPause)\n                  const PopupMenuItem(\n                    value: 'pause',\n                    child: Row(\n                      children: [\n                        Icon(Icons.pause, color: Colors.orange),\n                        SizedBox(width: 8),\n                        Text('Pause Task'),\n                      ],\n                    ),\n                  ),\n                if (task.canResume)\n                  const PopupMenuItem(\n                    value: 'resume',\n                    child: Row(\n                      children: [\n                        Icon(Icons.play_arrow, color: Colors.blue),\n                        SizedBox(width: 8),\n                        Text('Resume Task'),\n                      ],\n                    ),\n                  ),\n                if (task.canComplete)\n                  const PopupMenuItem(\n                    value: 'complete',\n                    child: Row(\n                      children: [\n                        Icon(Icons.check_circle, color: Colors.green),\n                        SizedBox(width: 8),\n                        Text('Complete Task'),\n                      ],\n                    ),\n                  ),\n              ],\n            ),\n          IconButton(\n            icon: const Icon(Icons.refresh),\n            onPressed: refreshTaskDetails,\n          ),\n        ],\n      ),\n      body: _isLoading\n          ? const Center(child: CircularProgressIndicator())\n          : RefreshIndicator(\n              onRefresh: _refreshTaskDetails,\n              child: SingleChildScrollView(\n                padding: const EdgeInsets.all(16),\n                child: Column(\n                  crossAxisAlignment: CrossAxisAlignment.start,\n                  children: [\n                    _buildTaskHeader(task),\n                    const SizedBox(height: 16),\n                    _buildOrderDetails(task),\n                    const SizedBox(height: 16),\n                    _buildTaskProgress(task),\n                    const SizedBox(height: 16),\n                    _buildTaskNotes(task),\n                    const SizedBox(height: 16),\n                    _buildTaskImages(task),\n                    if (!widget.isMyTask) ..[\n                      const SizedBox(height: 24),\n                      _buildAcceptTaskButton(task),\n                    ],\n                  ],\n                ),\n              ),\n            ),\n    );\n  }\n\n  Widget buildTaskHeader(WorkflowTask task) {\n    return Card(\n      elevation: 4,\n      child: Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            Row(\n              children: [\n                CircleAvatar(\n                  backgroundColor: _getStatusColor(task.status),\n                  child: Text(\n                    task.stageIcon,\n                    style: const TextStyle(fontSize: 20),\n                  ),\n                ),\n                const SizedBox(width: 16),\n                Expanded(\n                  child: Column(\n                    crossAxisAlignment: CrossAxisAlignment.start,\n                    children: [\n                      Text(\n                        task.stageName,\n                        style: const TextStyle(\n                          fontSize: 20,\n                          fontWeight: FontWeight.bold,\n                        ),\n                      ),\n                      Text(\n                        'Order #${task.orderId}',\n                        style: TextStyle(\n                          fontSize: 16,\n                          color: Colors.grey[600],\n                        ),\n                      ),\n                    ],\n                  ),\n                ),\n                Container(\n                  padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),\n                  decoration: BoxDecoration(\n                    color: _getStatusColor(task.status).withOpacity(0.1),\n                    borderRadius: BorderRadius.circular(20),\n                    border: Border.all(color: _getStatusColor(task.status)),\n                  ),\n                  child: Text(\n                    task.status.toUpperCase(),\n                    style: TextStyle(\n                      color: _getStatusColor(task.status),\n                      fontWeight: FontWeight.bold,\n                      fontSize: 12,\n                    ),\n                  ),\n                ),\n              ],\n            ),\n            if (task.priority > 3) ..[\n              const SizedBox(height: 12),\n              Container(\n                padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),\n                decoration: BoxDecoration(\n                  color: Colors.red.withOpacity(0.1),\n                  borderRadius: BorderRadius.circular(20),\n                  border: Border.all(color: Colors.red),\n                ),\n                child: Row(\n                  mainAxisSize: MainAxisSize.min,\n                  children: [\n                    const Icon(Icons.priority_high, size: 16, color: Colors.red),\n                    const SizedBox(width: 4),\n                    Text(\n                      'HIGH PRIORITY',\n                      style: TextStyle(\n                        color: Colors.red[700],\n                        fontWeight: FontWeight.bold,\n                        fontSize: 12,\n                      ),\n                    ),\n                  ],\n                ),\n              ),\n            ],\n            if (task.assignedToName != null) ..[\n              const SizedBox(height: 12),\n              Row(\n                children: [\n                  const Icon(Icons.person, size: 16, color: Colors.grey),\n                  const SizedBox(width: 4),\n                  Text(\n                    'Assigned to: ${task.assignedToName}',\n                    style: TextStyle(color: Colors.grey[600]),\n                  ),\n                ],\n              ),\n            ],\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget buildOrderDetails(WorkflowTask task) {\n    return Card(\n      child: Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            const Text(\n              'Order Details',\n              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),\n            ),\n            const SizedBox(height: 12),\n            buildDetailRow('Customer', task.orderDetails['customerName'] ?? 'Unknown'),\n            buildDetailRow('Phone', task.orderDetails['customerPhone'] ?? 'N/A'),\n            buildDetailRow('Garment', task.orderDetails['garmentType'] ?? 'N/A'),\n            buildDetailRow('Total Amount', '₹${task.orderDetails['totalAmount'] ?? 0}'),\n            buildDetailRow('Delivery Date', _formatDate(task.orderDetails['deliveryDate'])),\n            if (task.orderDetails['measurements'] != null) ..[\n              const SizedBox(height: 8),\n              const Text(\n                'Measurements:',\n                style: TextStyle(fontWeight: FontWeight.w600),\n              ),\n              const SizedBox(height: 4),\n              ...((task.orderDetails['measurements'] as Map<String, dynamic>).entries\n                  .map((e) => Padding(\n                        padding: const EdgeInsets.only(left: 16, top: 2),\n                        child: Text('${e.key}: ${e.value}'),\n                      ))),\n            ],\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget buildDetailRow(String label, String value) {\n    return Padding(\n      padding: const EdgeInsets.only(bottom: 8),\n      child: Row(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          SizedBox(\n            width: 100,\n            child: Text(\n              '$label:',\n              style: const TextStyle(fontWeight: FontWeight.w600),\n            ),\n          ),\n          Expanded(\n            child: Text(value),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget buildTaskProgress(WorkflowTask task) {\n    return Card(\n      child: Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            const Text(\n              'Task Progress',\n              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),\n            ),\n            const SizedBox(height: 12),\n            if (task.startedAt != null)\n              buildProgressItem(\n                'Started',\n                _formatDateTime(task.startedAt!),\n                Icons.play_arrow,\n                Colors.green,\n              ),\n            if (task.pausedAt != null)\n              buildProgressItem(\n                'Paused',\n                _formatDateTime(task.pausedAt!),\n                Icons.pause,\n                Colors.orange,\n              ),\n            if (task.resumedAt != null)\n              buildProgressItem(\n                'Resumed',\n                _formatDateTime(task.resumedAt!),\n                Icons.play_arrow,\n                Colors.blue,\n              ),\n            if (task.completedAt != null)\n              buildProgressItem(\n                'Completed',\n                _formatDateTime(task.completedAt!),\n                Icons.check_circle,\n                Colors.purple,\n              ),\n            if (task.timeSpent != null) ..[\n              const SizedBox(height: 8),\n              Container(\n                padding: const EdgeInsets.all(12),\n                decoration: BoxDecoration(\n                  color: Colors.blue.withOpacity(0.1),\n                  borderRadius: BorderRadius.circular(8),\n                ),\n                child: Row(\n                  children: [\n                    const Icon(Icons.timer, color: Colors.blue),\n                    const SizedBox(width: 8),\n                    Text(\n                      'Time Spent: ${_formatDuration(task.timeSpent!)}',\n                      style: const TextStyle(\n                        fontWeight: FontWeight.w600,\n                        color: Colors.blue,\n                      ),\n                    ),\n                  ],\n                ),\n              ),\n            ],\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget buildProgressItem(String label, String time, IconData icon, Color color) {\n    return Padding(\n      padding: const EdgeInsets.only(bottom: 8),\n      child: Row(\n        children: [\n          Icon(icon, color: color, size: 20),\n          const SizedBox(width: 8),\n          Text(\n            '$label:',\n            style: const TextStyle(fontWeight: FontWeight.w600),\n          ),\n          const SizedBox(width: 8),\n          Text(time),\n        ],\n      ),\n    );\n  }\n\n  Widget buildTaskNotes(WorkflowTask task) {\n    return Card(\n      child: Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            const Text(\n              'Notes',\n              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),\n            ),\n            const SizedBox(height: 12),\n            if (task.notes?.isNotEmpty == true)\n              Container(\n                width: double.infinity,\n                padding: const EdgeInsets.all(12),\n                decoration: BoxDecoration(\n                  color: Colors.grey[100],\n                  borderRadius: BorderRadius.circular(8),\n                ),\n                child: Text(task.notes!),\n              )\n            else\n              Text(\n                'No notes available',\n                style: TextStyle(color: Colors.grey[600]),\n              ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget buildTaskImages(WorkflowTask task) {\n    return Card(\n      child: Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            const Text(\n              'Images',\n              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),\n            ),\n            const SizedBox(height: 12),\n            if (task.images.isNotEmpty)\n              GridView.builder(\n                shrinkWrap: true,\n                physics: const NeverScrollableScrollPhysics(),\n                gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(\n                  crossAxisCount: 3,\n                  crossAxisSpacing: 8,\n                  mainAxisSpacing: 8,\n                ),\n                itemCount: task.images.length,\n                itemBuilder: (context, index) {\n                  return ClipRRect(\n                    borderRadius: BorderRadius.circular(8),\n                    child: Image.network(\n                      task.images[index],\n                      fit: BoxFit.cover,\n                      errorBuilder: (context, error, stackTrace) {\n                        return Container(\n                          color: Colors.grey[300],\n                          child: const Icon(Icons.error),\n                        );\n                      },\n                    ),\n                  );\n                },\n              )\n            else\n              Text(\n                'No images available',\n                style: TextStyle(color: Colors.grey[600]),\n              ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget buildAcceptTaskButton(WorkflowTask task) {\n    return SizedBox(\n      width: double.infinity,\n      child: ElevatedButton(\n        onPressed: () => acceptTask(task),\n        style: ElevatedButton.styleFrom(\n          backgroundColor: Colors.green,\n          foregroundColor: Colors.white,\n          padding: const EdgeInsets.symmetric(vertical: 16),\n        ),\n        child: const Text(\n          'Accept This Task',\n          style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold),\n        ),\n      ),\n    );\n  }\n\n  Future<void> handleMenuAction(String action, WorkflowTask task) async {\n    switch (action) {\n      case 'start':\n        await _startTask(task);\n        break;\n      case 'pause':\n        await _pauseTask(task);\n        break;\n      case 'resume':\n        await _resumeTask(task);\n        break;\n      case 'complete':\n        _showCompletionDialog();\n        break;\n    }\n  }\n\n  Future<void> acceptTask(WorkflowTask task) async {\n    final user = ref.read(authProvider);\n    if (user != null) {\n      setState(() => _isLoading = true);\n      final success = await WorkflowService.acceptTask(
        staffId: user.uid,
        orderId: task.orderId,
        stageId: task.stageId,
        token: user.jwt,
      );\n      setState(() => _isLoading = false);\n      \n      if (success) {\n        showSuccessSnackBar('Task accepted successfully');\n        widget.onTaskUpdated();\n        Navigator.pop(context);\n      } else {\n        showErrorSnackBar('Failed to accept task');\n      }\n    }\n  }\n\n  Future<void> startTask(WorkflowTask task) async {\n    final user = ref.read(authProvider);\n    if (user != null) {\n      setState(() => _isLoading = true);\n      final success = await workflowService.startTask(task.id, user.uid);\n      setState(() => _isLoading = false);\n      \n      if (success) {\n        showSuccessSnackBar('Task started successfully');\n        await refreshTaskDetails();\n        widget.onTaskUpdated();\n      } else {\n        showErrorSnackBar('Failed to start task');\n      }\n    }\n  }\n\n  Future<void> pauseTask(WorkflowTask task) async {\n    final user = ref.read(authProvider);\n    if (user != null) {\n      setState(() => _isLoading = true);\n      final success = await workflowService.pauseTask(task.id, user.uid);\n      setState(() => _isLoading = false);\n      \n      if (success) {\n        showSuccessSnackBar('Task paused successfully');\n        await refreshTaskDetails();\n        widget.onTaskUpdated();\n      } else {\n        showErrorSnackBar('Failed to pause task');\n      }\n    }\n  }\n\n  Future<void> resumeTask(WorkflowTask task) async {\n    final user = ref.read(authProvider);\n    if (user != null) {\n      setState(() => _isLoading = true);\n      final success = await workflowService.resumeTask(task.id, user.uid);\n      setState(() => _isLoading = false);\n      \n      if (success) {\n        showSuccessSnackBar('Task resumed successfully');\n        await refreshTaskDetails();\n        widget.onTaskUpdated();\n      } else {\n        showErrorSnackBar('Failed to resume task');\n      }\n    }\n  }\n\n  void showCompletionDialog() {\n    showDialog(\n      context: context,\n      barrierDismissible: false,\n      builder: (context) => AlertDialog(\n        title: const Text('Complete Task'),\n        content: SingleChildScrollView(\n          child: Column(\n            mainAxisSize: MainAxisSize.min,\n            children: [\n              TextField(\n                controller: _notesController,\n                decoration: const InputDecoration(\n                  labelText: 'Completion Notes',\n                  hintText: 'Add any notes about the completed work...',\n                  border: OutlineInputBorder(),\n                ),\n                maxLines: 3,\n              ),\n              const SizedBox(height: 16),\n              Row(\n                children: [\n                  const Text('Quality Rating: '),\n                  Expanded(\n                    child: Slider(\n                      value: _qualityRating.toDouble(),\n                      min: 1,\n                      max: 5,\n                      divisions: 4,\n                      label: _qualityRating.toString(),\n                      onChanged: (value) {\n                        setState(() {\n                          _qualityRating = value.round();\n                        });\n                      },\n                    ),\n                  ),\n                  Text('$_qualityRating/5'),\n                ],\n              ),\n              const SizedBox(height: 16),\n              ElevatedButton(\n                onPressed: _pickImages,\n                child: const Text('Add Images'),\n              ),\n              if (_selectedImages.isNotEmpty) ..[\n                const SizedBox(height: 8),\n                Text('${_selectedImages.length} images selected'),\n              ],\n            ],\n          ),\n        ),\n        actions: [\n          TextButton(\n            onPressed: () => Navigator.pop(context),\n            child: const Text('Cancel'),\n          ),\n          ElevatedButton(\n            onPressed: _completeTask,\n            child: const Text('Complete Task'),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Future<void> pickImages() async {\n    final List<XFile> images = await imagePicker.pickMultiImage();\n    if (images.isNotEmpty) {\n      setState(() {\n        selectedImages.addAll(images.map((image) => image.path));\n      });\n    }\n  }\n\n  Future<void> completeTask() async {\n    final user = ref.read(authProvider);\n    if (user != null) {\n      Navigator.pop(context); // Close dialog\n      setState(() => _isLoading = true);\n      \n      final success = await _workflowService.completeTask(\n        widget.task.id,\n        user.uid,\n        notes: _notesController.text.trim().isEmpty ? null : _notesController.text.trim(),\n        images: _selectedImages,\n        qualityRating: _qualityRating,\n      );\n      \n      setState(() => _isLoading = false);\n      \n      if (success) {\n        _showSuccessSnackBar('Task completed successfully');\n        widget.onTaskUpdated();\n        Navigator.pop(context);\n      } else {\n        _showErrorSnackBar('Failed to complete task');\n      }\n    }\n  }\n\n  Color _getStatusColor(String status) {\n    switch (status) {\n      case TaskStatus.pending:\n        return Colors.grey;\n      case TaskStatus.assigned:\n        return Colors.blue;\n      case TaskStatus.started:\n      case TaskStatus.resumed:\n        return Colors.green;\n      case TaskStatus.paused:\n        return Colors.orange;\n      case TaskStatus.completed:\n        return Colors.purple;\n      default:\n        return Colors.grey;\n    }\n  }\n\n  String _formatDate(dynamic date) {\n    if (date == null) return 'N/A';\n    try {\n      final DateTime dateTime = date is String ? DateTime.parse(date) : date;\n      return '${dateTime.day}/${dateTime.month}/${dateTime.year}';\n    } catch (e) {\n      return 'Invalid date';\n    }\n  }\n\n  String _formatDateTime(DateTime dateTime) {\n    return '${dateTime.day}/${dateTime.month}/${dateTime.year} ${dateTime.hour}:${dateTime.minute.toString().padLeft(2, '0')}';\n  }\n\n  String _formatDuration(Duration duration) {\n    final hours = duration.inHours;\n    final minutes = duration.inMinutes.remainder(60);\n    if (hours > 0) {\n      return '${hours}h ${minutes}m';\n    }\n    return '${minutes}m';\n  }\n\n  void _showSuccessSnackBar(String message) {\n    ScaffoldMessenger.of(context).showSnackBar(\n      SnackBar(\n        content: Text(message),\n        backgroundColor: Colors.green,\n        behavior: SnackBarBehavior.floating,\n      ),\n    );\n  }\n\n  void _showErrorSnackBar(String message) {\n    ScaffoldMessenger.of(context).showSnackBar(\n      SnackBar(\n        content: Text(message),\n        backgroundColor: Colors.red,\n        behavior: SnackBarBehavior.floating,\n      ),\n    );\n  }\n}